"""
Benchmark test for TrustedLLM privacy detection accuracy.

Tests the accuracy of originalToPlaceholder mappings generated by
the TrustedLLM's DetectMappings call (stateless mode, no session).
"""

import json
import os
import re
import sys
import time
from concurrent.futures import ThreadPoolExecutor, as_completed
from dataclasses import dataclass, field
from pathlib import Path
from typing import Dict, List, Optional

import requests


class BenchmarkRuntimeError(RuntimeError):
    """Raised when the benchmark cannot complete a case due to runtime/integration errors."""

# ── Data structures ──────────────────────────────────────────────────


@dataclass
class TrustedLLMConfig:
    base_url: str
    api_key: str
    model: str
    system_prompt: str
    temperature: float = 0.7


@dataclass
class TestCase:
    prompt: str
    expected: Dict[str, str]  # original -> placeholder


@dataclass
class FailEntry:
    prompt: str
    expected: Dict[str, str]
    actual: Dict[str, str]


@dataclass
class RuntimeErrorEntry:
    prompt: str
    error: str


@dataclass
class CaseResult:
    actual: Optional[Dict[str, str]] = None
    fail_entry: Optional[FailEntry] = None
    runtime_error: Optional[RuntimeErrorEntry] = None


@dataclass
class BenchmarkResult:
    total: int = 0
    success: int = 0
    fail: int = 0
    runtime_error: int = 0
    fail_list: List[FailEntry] = field(default_factory=list)
    runtime_error_list: List[RuntimeErrorEntry] = field(default_factory=list)


# ── Placeholder validation (matches Go code) ────────────────────────

PLACEHOLDER_PATTERN = re.compile(r"^\$\{[A-Z_]+[0-9]+\}$")


def validate_placeholder(placeholder: str) -> bool:
    """Validate placeholder format matches ${TYPE_N} pattern."""
    return bool(PLACEHOLDER_PATTERN.match(placeholder))


# ── TrustedLLM processRequest (stateless, Python reimplementation) ──

# JSON Schema for structured output (matches Go trustedLLMResponseSchema)
RESPONSE_SCHEMA = {
    "type": "object",
    "additionalProperties": False,
    "required": ["entries"],
    "properties": {
        "entries": {
            "type": "array",
            "items": {
                "type": "object",
                "additionalProperties": False,
                "required": ["original", "placeholder", "type"],
                "properties": {
                    "original": {"type": "string"},
                    "placeholder": {"type": "string"},
                    "type": {"type": "string"},
                },
            },
        },
    },
}


def build_user_prompt(known_mappings: Dict[str, str], text: str) -> str:
    """Build the user prompt sent to TrustedLLM (matches Go buildTrustedLLMUserPrompt)."""
    known_json = json.dumps(known_mappings, ensure_ascii=False)
    return f"已知映射：{known_json}\n待检测文本：{text}\n请识别新的敏感信息，并仅返回严格 JSON 对象。"


def detect_mappings(config: TrustedLLMConfig, text: str) -> Dict[str, str]:
    """
    Call TrustedLLM to detect sensitive information and return
    originalToPlaceholder mapping (stateless mode, no session).

    This reimplements the Go processRequest stateless path:
    1. Start with empty known mappings
    2. Call TrustedLLM DetectMappings with the text
    3. Parse response entries into originalToPlaceholder map
    """
    known_mappings: Dict[str, str] = {}

    user_prompt = build_user_prompt(known_mappings, text)

    request_body = {
        "model": config.model,
        "messages": [
            {"role": "system", "content": config.system_prompt},
            {"role": "user", "content": user_prompt},
        ],
        "temperature": config.temperature,
        "enable_thinking": False,
        "response_format": {
            "type": "json_schema",
            "json_schema": {
                "name": "trusted_llm_mapping_response",
                "strict": True,
                "schema": RESPONSE_SCHEMA,
            },
        },
    }

    url = config.base_url.rstrip("/") + "/chat/completions"
    headers = {"Content-Type": "application/json"}
    if config.api_key:
        headers["Authorization"] = f"Bearer {config.api_key}"

    max_retries = 3
    resp = None
    for attempt in range(max_retries):
        try:
            resp = requests.post(url, headers=headers, json=request_body, timeout=120)
        except requests.RequestException as e:
            if attempt < max_retries - 1:
                wait = 2 * (attempt + 1)
                print(f"    Retry {attempt+1}/{max_retries} after {wait}s (request error: {e})")
                time.sleep(wait)
                continue
            raise BenchmarkRuntimeError(
                f"TrustedLLM request failed after {max_retries} attempts: {e}"
            ) from e

        if 200 <= resp.status_code < 300:
            break
        if attempt < max_retries - 1:
            wait = 2 * (attempt + 1)
            print(f"    Retry {attempt+1}/{max_retries} after {wait}s (status {resp.status_code})")
            time.sleep(wait)
        else:
            raise BenchmarkRuntimeError(
                f"TrustedLLM returned status {resp.status_code} after {max_retries} attempts: {resp.text[:500]}"
            )

    if resp is None:
        raise BenchmarkRuntimeError("TrustedLLM request did not produce a response")

    try:
        payload = resp.json()
    except json.JSONDecodeError as e:
        raise BenchmarkRuntimeError(
            f"TrustedLLM response is not valid JSON: {resp.text[:500]}"
        ) from e

    # Extract content from OpenAI format response (matches Go extractOpenAIResponseContent)
    choices = payload.get("choices", [])
    if not choices:
        raise BenchmarkRuntimeError(
            f"TrustedLLM response missing choices field: {json.dumps(payload, ensure_ascii=False)[:500]}"
        )

    message = choices[0].get("message", {})
    content = message.get("content", "")
    if isinstance(content, list):
        content = "\n".join(
            part.get("text", "") for part in content if isinstance(part, dict) and part.get("text")
        )

    if not isinstance(content, str) or not content.strip():
        raise BenchmarkRuntimeError(
            f"TrustedLLM response content is empty or invalid: {json.dumps(payload, ensure_ascii=False)[:500]}"
        )

    try:
        response_data = json.loads(content)
    except json.JSONDecodeError as e:
        raise BenchmarkRuntimeError(
            f"TrustedLLM message content is not valid JSON: {content[:500]}"
        ) from e

    entries = response_data.get("entries")
    if not isinstance(entries, list):
        raise BenchmarkRuntimeError(
            f"TrustedLLM mapping response missing valid entries field: {json.dumps(response_data, ensure_ascii=False)[:500]}"
        )

    original_to_placeholder: Dict[str, str] = {}
    for entry in entries:
        if not isinstance(entry, dict):
            continue

        original = entry.get("original", "")
        placeholder = entry.get("placeholder", "")
        entry_type = entry.get("type", "")

        if not original or not placeholder or not entry_type:
            continue

        if not validate_placeholder(placeholder):
            print(f"Warning: invalid placeholder format: {placeholder}, skipping")
            continue

        original_to_placeholder[original] = placeholder

    return original_to_placeholder


# ── Comparison modes ──────────────────────────────────────────────────

# STRICT: 不关心序号，只要求 original 和 placeholder 的 TYPE 部分一致
#   例如 {"320102199001011234": "${ID_CARD_1}"} vs {"320102199001011234": "${ID_CARD_2"} => PASS
#   例如 {"320102199001011234": "${ID_CARD_1}"} vs {"320102199001011234": "${PHONE_1}"}  => FAIL
# LOOSE: 只检查 KEY（original）是否被识别到，右侧 placeholder 完全不关心
#   例如 {"320102199001011234": "${ID_CARD_1}"} vs {"320102199001011234": "${PHONE_1}"}  => PASS
# EXACT: 完全一致匹配（原有逻辑）

PLACEHOLDER_TYPE_PATTERN = re.compile(r"^\$\{([A-Z_]+)[0-9]+\}$")


def extract_placeholder_type(placeholder: str) -> Optional[str]:
    """Extract the TYPE part from a placeholder like ${PHONE_1} -> PHONE."""
    m = PLACEHOLDER_TYPE_PATTERN.match(placeholder)
    if m:
        return m.group(1)
    return None


def compare_mappings(expected: Dict[str, str], actual: Dict[str, str], mode: str = "strict") -> bool:
    """
    Compare expected and actual mappings according to the given mode.

    Modes:
      - "exact":  original 和 placeholder 必须完全一致
      - "strict": 不关心序号，original 必须一致且 placeholder TYPE 必须一致
      - "loose":  只关心 original 是否被识别到，placeholder 完全不关心
    """
    if mode == "exact":
        return expected == actual

    if mode == "loose":
        # 只检查 expected 中的所有 key 是否都出现在 actual 中
        return set(expected.keys()) == set(actual.keys())

    if mode == "strict":
        # original 必须一致，placeholder 的 TYPE 部分必须一致（序号不重要）
        if set(expected.keys()) != set(actual.keys()):
            return False
        for key in expected:
            expected_type = extract_placeholder_type(expected[key])
            actual_type = extract_placeholder_type(actual[key])
            if expected_type != actual_type:
                return False
        return True

    raise ValueError(f"Unknown comparison mode: {mode}")


# ── Single benchmark test ────────────────────────────────────────────


def test_benchmark(
    config: TrustedLLMConfig, test_case: TestCase, mode: str = "strict"
) -> CaseResult:
    """
    Run a single benchmark test case.

    - Mapping mismatch: treated as benchmark failure (model/prompt quality issue)
    - Request/response/runtime issue: treated as runtime error (program/integration issue)
    """
    try:
        actual = detect_mappings(config, test_case.prompt)
    except BenchmarkRuntimeError as e:
        return CaseResult(
            runtime_error=RuntimeErrorEntry(prompt=test_case.prompt, error=str(e))
        )
    except Exception as e:
        return CaseResult(
            runtime_error=RuntimeErrorEntry(
                prompt=test_case.prompt,
                error=f"Unexpected benchmark error: {e}",
            )
        )

    if compare_mappings(test_case.expected, actual, mode):
        return CaseResult(actual=actual)

    return CaseResult(
        actual=actual,
        fail_entry=FailEntry(
            prompt=test_case.prompt,
            expected=test_case.expected,
            actual=actual,
        ),
    )


# ── Loaders ──────────────────────────────────────────────────────────


def load_trusted_llm(env_path: str = None) -> TrustedLLMConfig:
    """
    Load TrustedLLM config from .env file.
    Env file format:
        trustedllm_url=https://api.cerebras.ai
        trustedllm_api_key=csk-xxx
        trustedllm_model=llama3.1-8b
    """
    if env_path is None:
        env_path = str(Path(__file__).parent / ".env")

    config = {}
    with open(env_path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            # Support both = and := separators
            if ":=" in line:
                key, value = line.split(":=", 1)
            elif "=" in line:
                key, value = line.split("=", 1)
            else:
                continue
            key = key.strip().lower()
            value = value.strip()
            config[key] = value

    system_prompt = load_system_prompt()

    return TrustedLLMConfig(
        base_url=config.get("trustedllm_url", ""),
        api_key=config.get("trustedllm_api_key", ""),
        model=config.get("trustedllm_model", ""),
        system_prompt=system_prompt,
    )


def load_system_prompt() -> str:
    """
    Load system prompt from TrustedLLMSystemPrompt.md
    in the same directory as this script.
    """
    prompt_path = Path(__file__).parent / "TrustedLLMSystemPrompt.md"
    with open(prompt_path, "r", encoding="utf-8") as f:
        return f.read().strip()


def load_test_data(data_path: str = None) -> List[TestCase]:
    """
    Load test data from JSONL file.
    Each line is a JSON object:
        {"prompt": "My phone is 13812345678", "expected": {"13812345678": "${PHONE_1}"}}
    """
    if data_path is None:
        data_path = str(Path(__file__).parent / "testdata.jsonl")

    cases: List[TestCase] = []
    with open(data_path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            obj = json.loads(line)
            cases.append(
                TestCase(
                    prompt=obj["prompt"],
                    expected=obj["expected"],
                )
            )
    return cases


# ── Result output ────────────────────────────────────────────────────


def write_result(result: BenchmarkResult, output_path: str = None, mode: str = "strict"):
    """Write benchmark result to JSON file."""
    if output_path is None:
        output_path = str(Path(__file__).parent / "benchmark_result.json")

    result_dict = {
        "total": result.total,
        "success": result.success,
        "fail": result.fail,
        "runtime_error": result.runtime_error,
        "mode": mode,
        "fail_list": [
            {
                "prompt": entry.prompt,
                "expected": entry.expected,
                "actual": entry.actual,
            }
            for entry in result.fail_list
        ],
        "runtime_error_list": [
            {
                "prompt": entry.prompt,
                "error": entry.error,
            }
            for entry in result.runtime_error_list
        ],
    }

    with open(output_path, "w", encoding="utf-8") as f:
        json.dump(result_dict, f, ensure_ascii=False, indent=2)

    print(f"Result written to {output_path}")


# ── Main ─────────────────────────────────────────────────────────────


def main():
    import argparse

    parser = argparse.ArgumentParser(description="Benchmark TrustedLLM privacy detection accuracy")
    parser.add_argument(
        "--mode",
        choices=["strict", "loose", "exact"],
        default="loose",
        help="Comparison mode: loose (only key match, default), strict (type must match, number ignored), exact (full match)",
    )
    parser.add_argument("--concurrency", type=int, default=None, help="Concurrency (default: 2)")
    parser.add_argument("--env", type=str, default=None, help="Path to .env file")
    parser.add_argument("--data", type=str, default=None, help="Path to testdata file")
    parser.add_argument("--output", type=str, default=None, help="Path to output result file")
    args = parser.parse_args()

    mode = args.mode
    concurrency = args.concurrency or int(os.environ.get("BENCHMARK_CONCURRENCY", "2"))
    env_path = args.env or os.environ.get("BENCHMARK_ENV", str(Path(__file__).parent / ".env"))
    data_path = args.data or os.environ.get(
        "BENCHMARK_DATA", str(Path(__file__).parent / "testdata.jsonl")
    )
    output_path = args.output or os.environ.get(
        "BENCHMARK_OUTPUT", str(Path(__file__).parent / "benchmark_result.json")
    )

    config = load_trusted_llm(env_path)
    test_cases = load_test_data(data_path)

    print(f"Loaded {len(test_cases)} test cases")
    print(f"TrustedLLM: model={config.model}, base_url={config.base_url}")
    print(f"Concurrency: {concurrency}")
    print(f"Mode: {mode}")
    print()

    result = BenchmarkResult(total=len(test_cases))

    with ThreadPoolExecutor(max_workers=concurrency) as executor:
        futures = {
            executor.submit(test_benchmark, config, tc, mode): i
            for i, tc in enumerate(test_cases)
        }

        for future in as_completed(futures):
            idx = futures[future]
            tc = test_cases[idx]
            case_result = future.result()

            if case_result.runtime_error is not None:
                result.runtime_error += 1
                result.runtime_error_list.append(case_result.runtime_error)
                print(f"  [ERROR] {tc.prompt}")
                print(f"    error: {case_result.runtime_error.error}")
                continue

            if case_result.fail_entry is None:
                result.success += 1
                print(f"  [PASS] {tc.prompt}")
            else:
                result.fail += 1
                result.fail_list.append(case_result.fail_entry)
                print(f"  [FAIL] {tc.prompt}")
                print(f"    expected: {case_result.fail_entry.expected}")
                print(f"    actual:   {case_result.fail_entry.actual}")

    write_result(result, output_path, mode)

    print()
    print(
        f"Total: {result.total}, Success: {result.success}, Fail: {result.fail}, "
        f"RuntimeError: {result.runtime_error} (mode: {mode})"
    )

    # Only runtime/integration errors should fail CI.
    if result.runtime_error > 0:
        sys.exit(1)


if __name__ == "__main__":
    main()